package io.github.phiseecodyhsp.arcstory.storyMode;import io.github.phiseecodyhsp.arcstory.SetStage;import io.github.phiseecodyhsp.arcstory.Util;import io.github.phiseecodyhsp.arcstory.storage.Resources;import javafx.animation.FadeTransition;import javafx.animation.TranslateTransition;import javafx.scene.control.Label;import javafx.scene.image.Image;import javafx.scene.image.ImageView;import javafx.scene.layout.StackPane;import javafx.scene.paint.Color;import javafx.scene.shape.Polygon;import javafx.util.Duration;import org.jetbrains.annotations.NotNull;import java.util.ArrayList;import java.util.List;//TODOpublic class ChapterSelectionPane extends StackPane {    private static final double TRANS_TIME = 1;    private int currentActPane = 0;    private final StackPane actPanePane = new StackPane();    private final List<ActPane> actPanes = new ArrayList<>();    public ChapterSelectionPane(ActPane... actPanes) {        ImageView lastBg = new ImageView();        lastBg.setOpacity(0);        lastBg.setPreserveRatio(true);        lastBg.setFitWidth(Util.getScreenWidth());        ImageView currentBg = new ImageView();        currentBg.setPreserveRatio(true);        currentBg.setFitWidth(Util.getScreenWidth());        TranslateTransition toLeft = new TranslateTransition(Duration.seconds(TRANS_TIME), actPanePane);        toLeft.setToX(-SetStage.WIDTH);        toLeft.setInterpolator(Util.EASE_OUT);        TranslateTransition toRight = new TranslateTransition(Duration.seconds(TRANS_TIME), actPanePane);        toRight.setToX(SetStage.WIDTH);        toLeft.setInterpolator(Util.EASE_IN);        FadeTransition onLastBg = new FadeTransition(Duration.seconds(TRANS_TIME), lastBg);        onLastBg.setFromValue(1);        onLastBg.setToValue(0);        FadeTransition onCurrentBg = new FadeTransition(Duration.seconds(TRANS_TIME), currentBg);        onCurrentBg.setFromValue(0);        onCurrentBg.setToValue(1);        Polygon leftArrow = new Polygon(        );        Polygon rightArrow = new Polygon(        );        leftArrow.setOpacity(ChapterPane.StoryButtonPane.StoryButton.LOWEST_BRIGHTNESS);        leftArrow.setFill(Color.BLACK);        leftArrow.setTranslateX(0);        leftArrow.setEffect(ChapterPane.StoryButtonPane.StoryButton.SHADOW);        leftArrow.setOnMouseEntered(_ -> {            leftArrow.setFill(Color.BLACK);            leftArrow.setOpacity(ChapterPane.StoryButtonPane.StoryButton.LOWEST_BRIGHTNESS);        });        leftArrow.setOnMouseExited(_ -> {            leftArrow.setFill(Color.WHITE);            leftArrow.setOpacity(1);        });        leftArrow.setOnMouseClicked(_ -> {            toLeft.play();            currentActPane--;            lastBg.setImage(currentBg.getImage());            currentBg.setImage(new Image(this.actPanes.get(currentActPane).bgPath));            onLastBg.play();            onCurrentBg.play();            if (currentActPane == 0) {                leftArrow.setFill(Color.BLACK);                leftArrow.setOpacity(ChapterPane.StoryButtonPane.StoryButton.LOWEST_BRIGHTNESS);                leftArrow.setMouseTransparent(true);            }            if (currentActPane == this.actPanes.size() - 2) {                rightArrow.setFill(Color.WHITE);                rightArrow.setOpacity(1);                rightArrow.setMouseTransparent(false);            }        });        rightArrow.setTranslateX(0);        rightArrow.setFill(Color.WHITE);        rightArrow.setEffect(ChapterPane.StoryButtonPane.StoryButton.SHADOW);        rightArrow.setOnMouseClicked(_ -> {            toRight.play();            currentActPane++;            lastBg.setImage(currentBg.getImage());            currentBg.setImage(new Image(this.actPanes.get(currentActPane).bgPath));            onLastBg.play();            onCurrentBg.play();            if (currentActPane == this.actPanes.size() - 1) {                rightArrow.setFill(Color.BLACK);                rightArrow.setOpacity(ChapterPane.StoryButtonPane.StoryButton.LOWEST_BRIGHTNESS);                rightArrow.setMouseTransparent(true);            }            if (currentActPane == 1) {                leftArrow.setFill(Color.WHITE);                leftArrow.setOpacity(1);                leftArrow.setMouseTransparent(false);            }        });        rightArrow.setOnMouseEntered(_ -> {            rightArrow.setFill(Color.BLACK);            rightArrow.setOpacity(ChapterPane.StoryButtonPane.StoryButton.LOWEST_BRIGHTNESS);        });        rightArrow.setOnMouseExited(_ -> {            rightArrow.setFill(Color.WHITE);            rightArrow.setOpacity(1);        });        getChildren().addAll(lastBg, currentBg, actPanePane, leftArrow, rightArrow);        addAll(actPanes);    }    public void addAll(ActPane... actPanes) {        actPanePane.getChildren().addAll(actPanes);        this.actPanes.addAll(List.of(actPanes));        for (int i = 0; i < actPanePane.getChildren().size(); i++) {            this.actPanes.get(i).numberLabel.setText(intToRoman(i + 1));            this.actPanes.get(i).setTranslateX(i * SetStage.WIDTH);        }    }    private static String intToRoman(int num) {        if (num == 0) {            return "N";        }        int[] values = {1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1};        String[] symbols = {"M", "CM", "D", "CD", "C", "XC", "L", "XL", "X", "IX", "V", "IV", "I"};        StringBuilder roman = new StringBuilder();        if (num < 0) {            roman.append("-");            num = -num;        }        for (int i = 0; i < values.length; i++) {            while (num >= values[i]) {                roman.append(symbols[i]);                num -= values[i];            }        }        System.out.println(new Object());        return roman.toString();    }    public static class ActPane extends StackPane {        public final Label numberLabel = new Label();        public final String bgPath;        private ActPane(String name, @NotNull String bgPath, ChapterButton... buttons) {            Label nameLabel = new Label(name);            this.bgPath = bgPath;            getChildren().addAll(numberLabel, nameLabel);            addAll(buttons);        }        private void addAll(ChapterButton... buttons) {            getChildren().addAll(buttons);        }        //TODO        public static class ChapterButton extends StackPane {            private final ImageView neo = new ImageView(Resources.NEW_ICON);            private final ChapterPane chapterPane;            private ChapterButton(ChapterPane pane, @NotNull String imagePath) {                ImageView view = new ImageView(imagePath);                chapterPane = pane;                setOnMouseClicked(_ -> Util.getSetStage(this).switchPane(chapterPane));            }            public void checkNew() {                for (ChapterPane.StoryButtonPane storyButtonPane : chapterPane.getStoryButtonPanes()) {                    for (ChapterPane.StoryButtonPane.StoryButton storyButton : storyButtonPane.getStoryButtons()) {                        if (storyButton.isNew()) {                            if (!isNew()) {                                getChildren().add(neo);                            }                            return;                        }                    }                }                if (isNew()) {                    getChildren().remove(neo);                }            }            public boolean isNew() {                return getChildren().contains(neo);            }        }    }}